const brand = ($env.BRAND_NAME || '').toLowerCase();
const competitors = ($env.COMPETITOR_NAMES || '').toLowerCase().split(',').map(s=>s.trim()).filter(Boolean);
const watchTerms = [brand, ...competitors].filter(Boolean);
const threeDaysAgo = new Date(); threeDaysAgo.setDate(threeDaysAgo.getDate()-3);
const items = $input.all().map(i=>i.json).filter(item => {
  if (!watchTerms.length) return true;
  const text = ((item.title||'')+(item.contentSnippet||item.content||'')).toLowerCase();
  const recent = !item.isoDate || new Date(item.isoDate) >= threeDaysAgo;
  return recent && watchTerms.some(t=>t && text.includes(t));
}).map(i=>({ title: i.title, link: i.link, date: i.isoDate?.slice(0,10), snippet: (i.contentSnippet||'').slice(0,300), source: i.meta?.link || 'RSS' }));
return [{ json: { date: new Date().toISOString().slice(0,10), count: items.length, items, brand_name: $env.BRAND_NAME || 'Unknown' } }];

