const data = $('Filter Relevant Mentions').first().json;
let analysis;
try { analysis = JSON.parse(($input.first().json.message?.content||'{}').replace(/```json|```/g,'').trim()); } catch { analysis = {}; }
return [{ json: { date: data.date, brand_name: data.brand_name, raw_count: data.count, generated_at: new Date().toISOString(), ...analysis } }];

